import React, { useState, useEffect } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import NetInfo from '@react-native-community/netinfo';

const TokenGenerator = () => {
  const [isConnected, setIsConnected] = useState(true);
  const [token, setToken] = useState('');

  useEffect(() => {
    const unsubscribe = NetInfo.addEventListener(state => {
      setIsConnected(state.isConnected);
    });

    return () => unsubscribe();
  }, []);

  const generateToken = () => {
    const newToken = Math.random().toString(36).substr(2, 9);
    setToken(newToken);
    Alert.alert('Token Generated', `Your token is: ${newToken}`);
  };

  const handleAction = () => {
    if (!isConnected) {
      generateToken();
    } else {
      Alert.alert('Online Mode', 'You are connected to the internet.');
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Text>{isConnected ? 'You are online' : 'You are offline'}</Text>
      <Button title="Perform Action" onPress={handleAction} />
      {token ? <Text>Your Session Token: {token}</Text> : null}
    </View>
  );
};

export default TokenGenerator;